B.q2=s(["text","multiline","number","phone","datetime","emailAddress","url","visiblePassword","name","address","none","webSearch","twitter"],t.s)
B.q3=s(["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"],t.s)
B.O0=s(["J\u2019ai sacrifi\xe9 ma main pour encha\xeener un loup.","Je suis le dieu manchot de la justice et de la guerre h\xe9ro\xefque.","Mon nom est synonyme de courage."],t.s)
B.Sp=new A.cz("TYR",B.O0)
B.OV=s(["J\u2019ai \xe9chang\xe9 un \u0153il contre la sagesse.","Mes deux corbeaux parcourent le monde pour m\u2019informer.","Je suis le P\xe8re de Tout, r\xe9gnant depuis Asgard."],t.s)
B.Sj=new A.cz("ODIN",B.OV)
B.P3=s(["Mon char est tir\xe9 par des boucs.","Je suis le protecteur de Midgard et le fils d\u2019Odin.","Le tonnerre gronde quand je lance mon marteau."],t.s)
B.Sl=new A.cz("THOR",B.P3)
B.Nf=s(["Je suis le p\xe8re de monstres et le ma\xeetre de la tromperie.","Mon sang s\u2019est m\xeal\xe9 \xe0 celui d\u2019Odin.","Je change de forme comme je change d\u2019avis."],t.s)
B.Sk=new A.cz("LOKI",B.Nf)
B.OK=s(["Je pleure des larmes d\u2019or pour mon \xe9poux parti.","Je r\xe8gne sur le F\xf3lkvangr et re\xe7ois la moiti\xe9 des guerriers morts.","Mon collier, Br\xedsingamen, est le plus beau des tr\xe9sors."],t.s)
B.So=new A.cz("FREYA",B.OK)
B.NI=s(["Je connais le destin de tous, mais je garde le silence.","Je suis l\u2019\xe9pouse d\u2019Odin et la reine d\u2019Asgard.","J\u2019ai pleur\xe9 la mort de mon fils lumineux."],t.s)
B.Se=new A.cz("FRIGG",B.NI)
B.ND=s(["Ma m\xe2choire, une fois ouverte, touche le ciel et la terre.","Les dieux m\u2019ont encha\xeen\xe9 par la ruse avec un ruban de soie.","Je d\xe9vorerai Odin lors de la derni\xe8re bataille."],t.s)
B.Sg=new A.cz("FENRIR",B.ND)
B.MQ=s(["Je suis la forteresse des dieux Ases.","Mes murs ont \xe9t\xe9 construits par un g\xe9ant et son cheval.","Le pont arc-en-ciel m\xe8ne \xe0 mes portes."],t.s)
B.Sa=new A.cz("ASGARD",B.MQ)
B.OA=s(["Chaque matin, je pars pour ne revenir qu\u2019au soir.","Je suis la Pens\xe9e qui vole pour le P\xe8re de Tout.","Mon fr\xe8re est la M\xe9moire."],t.s)
B.St=new A.cz("HUGINN",B.OA)
B.ON=s(["Je suis un pont de feu gard\xe9 par un dieu vigilant.","Mes trois couleurs relient le monde des hommes \xe0 celui des dieux.","Je me briserai sous le poids des g\xe9ants \xe0 la fin des temps."],t.s)
B.Sq=new A.cz("BIFROST",B.ON)
B.Ov=s(["Je reviens toujours \xe0 la main de mon ma\xeetre.","Mon vol dans le ciel est le son du tonnerre.","Je suis le broyeur, terreur des g\xe9ants."],t.s)
B.Sh=new A.cz("MJOLNIR",B.Ov)
B.P1=s(["Je suis le royaume des mortels.","Un serpent g\xe9ant entoure mes c\xf4tes.","Je suis prot\xe9g\xe9 par le fils d\u2019Odin au marteau."],t.s)
